config.post_script:
-- ParadeDB post-load: Create BM25 index
CREATE INDEX hn_items_idx ON hn_items
USING bm25 (id, title, text, (by::pdb.literal), (type::pdb.literal), (url::pdb.literal), score, time)
WITH (key_field='id', target_segment_count = 32);

VACUUM ANALYZE hn_items;

script:
import db from "k6/x/database";

const backends = db.backends({
  datasetPath: "../",
  backends: [
  //  { type: "paradedb", alias: "paradedb-main", connection: "postgres://postgres:postgres@localhost:5443/benchmark", container: "paradedb-1", color: "blue" },
    { type: "paradedb", alias: "paradedb", connection: "postgres://postgres:postgres@localhost:5444/benchmark", container: "paradedb-2", color: "light purple" },
    "elasticsearch",
  ],
});

const arrays = [1, 2, 3, 5].map(n =>
  JSON.parse(open(`./search_terms_${n}.json`))
);

const interleaved = [];
const maxLen = Math.max(...arrays.map(a => a.length));

for (let i = 0; i < maxLen; i++) {
  for (const arr of arrays) {
    if (i < arr.length) {
      interleaved.push(arr[i]); // no ...
    }
  }
}

const all = JSON.parse(open("./search_terms.json"));

const multiTerms = [];
for (let i = 0; i < all.length - 2; i += 2) {
  multiTerms.push(`${all[i]} ${all[i + 1]} ${all[i + 2]}`);
}

const terms = new Map([
  ["single", db.terms(JSON.parse(open("./search_terms.json")))],
  ["two", db.terms(JSON.parse(open("./search_terms_2.json")))],
  ["three", db.terms(JSON.parse(open("./search_terms_3.json")))],
  ["multi", db.terms(multiTerms)]
]);


// Scenario timing 
const timer = db.timer({ duration: "30s", gap: "2s" });

const scenarios = {};

for (const [termName] of terms) {
  for (const backend of backends.getAll()) {
    const key = `${backend}_${termName}`;

    scenarios[key] = {
      executor: "constant-vus",
      vus: 1,
      duration: timer.duration(),
      startTime: timer.advanceAndGet(),
      exec: backend === "elasticsearch" ? "es_topk" : "pdb_topk",
      env: {
        BACKEND: backend,
        TERMS: termName,
      },
      tags: { chart: `${termName}_topk` },
    };
  }
}
//export const collectMetrics = backends.addDockerMetricsCollector(scenarios, timer);
export const options = { scenarios };

export function pdb_topk() {
  backends.get(__ENV.BACKEND).query(
    `SELECT id, title, by, score
     FROM hn_items
     WHERE title ||| $1
     ORDER BY pdb.score(id) DESC
     LIMIT 10`,
    terms.get(__ENV.TERMS).next()
  );
}

// ── Elasticsearch ───────────────────────────────────────────────────────────
export function es_topk() {
  backends.get(__ENV.BACKEND).query("hn_items", {
    query: { match: { title: terms.get(__ENV.TERMS).next() } },
    _source: ["id", "title", "by", "score"],
    size: 10,
  });
}
